(In reply to Matthias Andree from comment #4)

I think the following is a better simple analogy to the item_space and item_size code for investigating the behavior: it has the function prototype and K&R mix. Still it is a variation of your code. (I added a second parameter just becuase I was curious.)

Parts of the results are based on signed vs. unsigned formats.

# more db5_item_space_problem.c 
#include <stdio.h>
#include <stdlib.h>

long f(unsigned short int i, unsigned short int j);

int main(void) {
    long i = f(-17,40000);
    printf("in main: i=%ld\n", i);
    i = f(40000,-17);
    printf("in main: i=%ld\n", i);
    i = f(65536,65536);
    printf("in main: i=%ld\n", i);
    exit(0);
}

long f(i,j)
    unsigned short int i;
    unsigned short int j;
{
    printf("in f: i=%hd (as long: i=%ld)\n", i, (long)i);
    printf("in f: j=%hd (as long: j=%ld)\n", j, (long)j);
    return i;
}

